```class Solution {
    public int strongPasswordChecker(String password) {
        int missingLower = 0, missingUpper = 0, missingDigit = 0;
        for (char c : password.toCharArray()) {
            if (Character.isLowerCase(c)) missingLower++;
            if (Character.isUpperCase(c)) missingUpper++;
            if (Character.isDigit(c)) missingDigit++;
        }
        int need = Math.max(missingLower, Math.max(missingUpper, missingDigit));
        int delete = password.length() - 20;
        delete = delete < 0 ? 0 : delete;
        int replace = 0;
        for (int i = 0; i < password.length() - 2; i++) {
            if (password.charAt(i) == password.charAt(i + 1) && password.charAt(i) == password.charAt(i + 2)) {
                replace++;
                i += 2;
            }
        }
        return Math.max(need, Math.max(delete, replace));
    }
}```
